INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(11, 22, E'# HygieneLoop — Patient-Centric Dental Recall via Self-Scheduling\n\n## 1. Executive Summary\n\nHygieneLoop flips the traditional recall model: instead of the practice chasing patients, patients self-schedule their next cleaning before they leave the building. A post-visit text or email delivers a personalized scheduling link with the hygienist’s available slots pre-loaded. If the patient does not book within 7 days, an automated nurture sequence kicks in with progressively more urgent reminders and a one-tap booking button. The result: practices capture 60–70% of recall appointments at the point of care, dramatically reducing the volume that needs chasing later. HygieneLoop targets independent practices with 500–2,000 patients who are frustrated with recall calls going unanswered.\n\n**Core Insight**: The best time to book the next cleaning is the moment the patient is sitting in the chair feeling good about their teeth.\n\n**Year-1 Goals**:\n- 200 practices subscribed\n- 65% pre-booked recall rate among enrolled practices\n- MRR of $48,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| US independent dental practices | ~107,000 | ADA 2023 |\n| Target segment (500–2,000 active patients) | ~58,000 | ADA estimates |\n| % of patients currently pre-booking next visit | ~28% | AADOM 2023 survey |\n| Revenue per hygiene visit | $150–$220 | National avg |\n| Unfilled recall slots per practice per year | 340–520 | 18–23% no-show rate |\n| Revenue lost to unfilled recall | $51K–$114K/year | Range based on fee schedule |\n| Practices using online patient self-scheduling | ~34% | Dental Products Report 2023 |\n| Practices with recall-specific self-scheduling | <12% | Proprietary survey |\n| TAM | ~$290M/year | 58,000 × $417/mo avg |\n| Year-1 SOM | ~$576K | 200 × $240/mo |\n\n## 3. Competitive Landscape\n\n| Product | Scheduling Type | Patient Self-Serve | Post-Visit Automation | Price/mo | Weakness |\n|---------|----------------|--------------------|-----------------------|----------|----------|\n| Lighthouse 360 | Staff-initiated | Partial | No | $349–$499 | Push model, no self-serve |\n| NexHealth | Self-scheduling | Yes | Basic | $400–$700 | General scheduling, not recall-specific |\n| Zocdoc | Consumer search + booking | Yes | No | Revenue share | Only for new patients |\n| Solutionreach | Staff-initiated | No | No | $400–$600 | No self-scheduling |\n| Calendly (generic) | Self-scheduling | Yes | No | $16–20 | Not HIPAA, not dental |\n| **HygieneLoop** | **At-point-of-care + self-serve** | **Yes** | **Yes (nurture seq.)** | **$179–$249** | **New brand** |\n\n## 4. Target User Personas\n\n### Persona A: Patient Experience Champion — Dr. Megan Clarke\n- **Age**: 44, female, owns a modern 3-chair practice in Portland, OR\n- **Patient Panel**: 1,100 active patients, 2 hygienists\n- **Current Approach**: Has tried Lighthouse 360 but feels it’s “just sending spam”\n- **Pain Points**:\n  1. 22% of patients don’t respond to any recall reminder\n  2. Booking over the phone is slow; patients put it off\n  3. Hygienists see gaps in their schedule every day\n- **What She Wants**: Frictionless booking her patients actually use; no more front-desk phone tag\n- **WTP**: $199–$249/month\n\n### Persona B: Busy Front Desk Coordinator — Tyler Nguyen\n- **Age**: 28, male, front desk at a 4-dentist family practice in Phoenix\n- **Recall burden**: Spends 2.5 hours/day on outbound recall calls; answer rate under 25%\n- **Pain Points**:\n  1. Calling patients who never answer is demoralizing and inefficient\n  2. No way to know if a patient got the message and is just ignoring it vs. never received it\n  3. Rescheduling last-minute cancellations requires manually going through a waitlist notepad\n- **Goal**: Reduce outbound calls by 75%; fill cancellations automatically\n- **WTP**: Defers to dentist; frames as labor cost savings ($28K front-desk hours saved)\n\n### Persona C: Tech-Forward Associate Dentist — Dr. Kwame Asante\n- **Age**: 33, male, associate at a practice in Charlotte considering buying his own\n- **Interest**: Wants to set up a modern practice with minimal admin staff from day one\n- **WTP**: $149–$179/month starter; expects to scale up\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Post-visit self-scheduling link | P0 | Auto-sent SMS/email after visit with hygienist-specific open slots |\n| Smart scheduling window | P0 | Recall due date calculated from last visit + interval, slots pre-filtered |\n| Automated nurture sequence | P0 | 7-day, 30-day, 60-day follow-up if patient has not self-booked |\n| No-show tracking dashboard | P0 | Real-time view of booked vs. unbooked recall, overdue list |\n| PMS sync (Open Dental, Dentrix, Eaglesoft) | P1 | Pull appointment history; push new bookings back into PMS |\n| Cancellation backfill (waitlist) | P1 | Notify waitlist via SMS when slot opens; first-reply-wins booking |\n| Two-way SMS re-engagement | P1 | Patient can reply STOP, HELP, or BOOK to trigger a live link |\n| Custom recall intervals per patient | P1 | Perio maintenance (3 mo), standard (6 mo), high-risk (4 mo) |\n| Staff override dashboard | P2 | Front desk can manually send link, adjust due date, mark contacted |\n| Post-visit satisfaction survey | P2 | One-question NPS + Google review prompt after each visit |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. Stateless API with JWT auth. PostgreSQL 16 (AWS RDS, HIPAA-compliant). Redis for job queues (recall scheduling engine runs on cron + event triggers).\n\n**Scheduling Engine**: Time-slot availability pulled from PMS every 15 min. Patient-facing booking UI is a lightweight React SPA served from CloudFront (no auth required for patient; link includes signed token).\n\n**Messaging**: Twilio (SMS + voice), SendGrid (email). All outbound messages logged for audit trail. STOP/HELP keywords handled automatically per TCPA requirements.\n\n**PMS Integration**: Open Dental REST API (native); Dentrix G7 API; Eaglesoft via HL7 FHIR adapter. Bidirectional: pull schedule + appointments, push new recall bookings.\n\n**Security**: PHI encrypted at rest (AES-256) and in transit (TLS 1.3). BAAs with Twilio, SendGrid, AWS. RBAC for staff roles. Patient booking links expire after 72 hours.\n\n## 7. Business Model\n\n| Plan | Price/Month | Features | Patient Cap |\n|------|-------------|----------|-------------|\n| Starter | $149 | Self-scheduling link, 3-step nurture, basic dashboard | 800 patients |\n| Standard | $219 | + PMS sync, waitlist engine, custom recall intervals | 1,500 patients |\n| Pro | $279 | + Multi-hygienist management, satisfaction surveys, analytics export | 2,500 patients |\n| DSO | Custom | Multi-location, white-label, API access, dedicated CSM | Unlimited |\n\n**Additional Revenue**:\n- Onboarding setup fee: $199 (waived for annual commitment)\n- SMS overage: $0.014/message above monthly cap\n- Custom PMS connector: $59/month\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Post-visit SMS scheduling link, signed-token patient booking flow, basic slot availability engine, CSV patient import |\n| M2 | Weeks 5–8 | Automated nurture sequences (3-step), no-show tracking dashboard, Open Dental PMS sync, HIPAA infra |\n| M3 | Weeks 9–12 | Waitlist cancellation backfill, Dentrix sync, custom recall intervals, two-way SMS |\n| M4 | Weeks 13–16 | Eaglesoft sync, satisfaction survey module, Stripe billing, self-serve onboarding, referral program |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active practices | 35 | 200 |\n| Pre-booked recall rate (enrolled practices) | 45% | 65% |\n| MRR | $6,300 | $48,000 |\n| Monthly churn | <7% | <4% |\n| Avg time to first booking sent | <90 min after onboarding | <30 min |\n| Booking link click-through rate | >38% | >52% |\n| NPS | >42 | >58 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| PMS sync failures causing double-bookings | Medium | High | Read-only pull by default in M1; write-back only after 30-day reliability window; staff confirm before push |\n| TCPA / spam compliance violations | Medium | High | Honor STOP keywords immediately; obtain express written consent at point of care; retain consent records |\n| Patient adoption of self-scheduling link < expected | Medium | Medium | A/B test link placement (post-visit text vs. chairside QR code vs. checkout screen); iterate in M2 |\n| PMS vendor restricts API access | Low | High | Maintain CSV-based fallback for appointment data; negotiate API access agreements with vendors upfront |\n| Competitor (NexHealth) adds recall self-scheduling | Medium | Medium | Focus on indie practice simplicity and price; NexHealth targets larger practices at $400+ |\n| Staff resistance to changing recall workflow | Medium | Medium | Design for parallel operation: HygieneLoop supplements rather than replaces existing workflow in M1 |',
 E'[{"step": 1, "action": "Insight identification", "rationale": "Observed that post-visit booking conversion is 3x higher than cold outreach recall; designed product around capturing that moment."}, {"step": 2, "action": "Self-scheduling UX design", "rationale": "Patient-facing booking must require zero account creation; signed-token URL approach eliminates friction while maintaining security."}, {"step": 3, "action": "TCPA compliance review", "rationale": "Self-scheduling SMS falls under transactional communications but marketing nurture sequences require explicit opt-in; designed consent capture into checkout flow."}, {"step": 4, "action": "PMS integration architecture", "rationale": "Chose read-only pull for M1 to reduce risk of corrupting practice schedule; write-back added only after validation period."}, {"step": 5, "action": "Pricing model decision", "rationale": "Positioned below NexHealth ($400-700) and Lighthouse 360 ($349-499) while offering a feature that neither does well: frictionless patient self-scheduling."}, {"step": 6, "action": "Success metric design", "rationale": "Chose pre-booked recall rate as primary metric because it directly measures the core value proposition and is easy for dentists to understand."}]',
 'submitted', 44,
 NOW() - INTERVAL '18 days', NOW() - INTERVAL '18 days', NOW() - INTERVAL '18 days');

