INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(12, 9, E'# ClassPulse — Assignment Completion Tracker for K-8 Teachers\n\n## 1. Executive Summary\n\nClassPulse is a lightweight SaaS tool that gives K-8 teachers a real-time view of assignment completion across their class of 25–35 students. Teachers log assignments once; students (or teachers on their behalf) mark them complete; parents receive automated weekly digest reports highlighting their child’s completion rate and any missing work. ClassPulse surfaces struggling students early—before a missing homework pattern becomes a failing grade—by showing a color-coded risk heatmap updated daily. Unlike bloated LMS platforms, ClassPulse is designed to be fully operational in 20 minutes with zero IT support and no student login required for younger grades.\n\n**Core Problem**: Teachers spend 45–90 minutes per week manually tracking who turned in what. Parents find out their child is behind only at report card time. ClassPulse eliminates both problems.\n\n**Year-1 Goals**:\n- 1,200 active teacher accounts\n- Average weekly active usage: 4+ days per week\n- MRR of $18,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| K-8 public school teachers (US) | ~1.8M | NCES 2023 |\n| Average class size (K-8) | 22–32 students | NCES state-by-state |\n| Teachers without an LMS in use | ~38% | EdWeek Research Center 2023 |\n| Teachers using LMS but dissatisfied with homework tracking | ~44% | Proprietary survey N=180 |\n| Hours/week spent on manual homework tracking | 1–1.5 hrs | Teacher interview avg |\n| Annual teacher tools budget (per teacher, Title I) | $200–$500 | School district policy |\n| Parents wanting more frequent homework updates | 71% | NPTA 2023 Parent Survey |\n| TAM (K-8 teacher SaaS tools) | ~$360M/year | 1.8M × $200/yr |\n| SAM (teachers open to new tracking tools) | ~$108M/year | 30% reachable |\n| Year-1 SOM | ~$216K | 1,200 × $15/mo |\n\n## 3. Competitive Landscape\n\n| Product | Type | Price | Homework Tracking | Parent Reports | K-8 Focus | Weakness |\n|---------|------|-------|-------------------|----------------|-----------|----------|\n| Google Classroom | LMS | Free | Basic (turn-in) | No | No | No completion analytics or parent digests |\n| Seesaw | K-5 platform | Free / $120/yr | Portfolio-based | Yes | Yes | Not designed for homework completion rate tracking |\n| ClassDojo | Behavior + messaging | Free | No | Messaging only | Yes | No academic tracking |\n| Remind | Messaging | Free | No | No | No | Pure communication, no data |\n| Canvas (K-12) | Full LMS | $5–$10/student | Yes | Basic | No | Requires IT setup, too complex for indie teachers |\n| **ClassPulse** | **Completion tracker** | **$15/mo** | **Yes (core)** | **Yes (automated)** | **Yes** | **New brand** |\n\n## 4. Target User Personas\n\n### Persona A: Independent Elementary Teacher — Mrs. Jennifer Walsh\n- **Age**: 38, 3rd grade teacher in suburban Michigan, 28 students\n- **Current System**: Paper checklist + Google Sheets she updates manually each morning\n- **Pain Points**:\n  1. Takes 45 min each Monday to compile the previous week’s missing assignments\n  2. Parents email her asking why they weren’t told their child was missing 4 assignments\n  3. Identifying struggling students early requires cross-referencing multiple sheets\n- **Goal**: Spend less than 5 min/day on tracking; parents should know before she has to call them\n- **WTP**: $12–$15/month (pays personally; no school budget approval needed)\n\n### Persona B: Middle School Science Teacher — Mr. Darnell Brooks\n- **Age**: 44, 7th grade science teacher in urban Texas, 3 class periods × 30 students = 90 students\n- **Current System**: Google Classroom for assignment posting; manually tracks completion in Sheets\n- **Pain Points**:\n  1. Managing 90 students’ completion across 3 periods is chaotic\n  2. Google Classroom’s “missing” label doesn’t send parent notifications\n  3. He can see patterns (“Jayla always misses Thursdays”) but has no easy way to document them for parent conferences\n- **WTP**: $18–$22/month for multi-class support\n\n### Persona C: Grade-Level Team Lead — Maria Gonzalez\n- **Age**: 52, 5th grade team lead at a Title I school in California\n- **Use Case**: Wants a consistent tracking system across her 4-teacher grade-level team\n- **WTP**: $12/teacher/month; advocates for school-wide adoption at $8/teacher/month bulk\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Assignment entry (title, due date, subject, class) | P0 | One-click assignment creation; repeating assignment support |\n| Student completion marking | P0 | Teacher marks complete; optional: student self-report via code |\n| Class completion rate view | P0 | Live heatmap: green/yellow/red per student per assignment |\n| Struggling student alert | P0 | Flag any student missing >20% of assignments in rolling 2-week window |\n| Automated weekly parent digest email | P0 | Per-student summary: completed, missing, completion rate trend |\n| Multi-class support | P1 | Teachers with multiple periods manage all classes in one view |\n| Google Classroom import | P1 | Pull assignment list from Classroom; sync turn-in status |\n| Parent portal (read-only) | P1 | Parents log in to see their child’s live completion status |\n| Progress report PDF export | P1 | One-click report for parent-teacher conferences |\n| Behavior notes per student | P2 | Optional annotation alongside completion data |\n| School/grade-level admin view | P2 | Team lead sees aggregate completion rates across classes |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16 (Supabase hosted, FERPA-compliant). Redis for session caching.\n\n**Frontend**: Next.js 15, TailwindCSS 4. Class heatmap uses a lightweight React grid component (no heavy charting library). Mobile-responsive for teacher tablet use.\n\n**Parent Digest**: SendGrid transactional email. Digest compiled by a cron job every Sunday evening (teacher-configurable day). Email uses responsive HTML template with per-student completion data.\n\n**Google Classroom Integration**: Google Classroom API v1. OAuth 2.0 for teacher authorization. Pull course assignments and submission statuses.\n\n**Security**: FERPA compliance: student data minimization (no SSN, DOB optional, first name + last initial default). Parent accounts linked to student only after teacher-approved invite code. Data deletion on account close.\n\n## 7. Business Model\n\n| Plan | Price/Month | Classes | Students | Features |\n|------|-------------|---------|----------|----------|\n| Starter | $12 | 1 | Up to 35 | Core tracking, weekly parent digest, struggling student alerts |\n| Pro | $19 | Up to 5 | Up to 150 | + Google Classroom sync, parent portal, progress report export |\n| School | $8/teacher | Unlimited classes | Unlimited | + Admin dashboard, team reporting, priority support, bulk billing |\n\n**Revenue Mix**:\n- Individual teachers: 70% of accounts, higher churn\n- School/team plans: 30% of accounts, 60% of MRR, lower churn\n- Annual discount: 2 months free (reduces churn, improves cash flow)\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Assignment CRUD, completion marking, class heatmap, basic missing-work alert |\n| M2 | Weeks 5–8 | Automated weekly parent digest email, multi-class support, CSV student import |\n| M3 | Weeks 9–12 | Google Classroom sync, parent portal (read-only), progress report PDF export |\n| M4 | Weeks 13–16 | School admin view, Stripe billing, self-serve onboarding, referral program for teacher networks |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active teacher accounts | 150 | 1,200 |\n| Weekly active usage rate | >55% | >70% |\n| Parent digest open rate | >42% | >50% |\n| MRR | $2,100 | $18,000 |\n| Monthly churn (individual) | <9% | <6% |\n| Monthly churn (school plans) | <3% | <2% |\n| NPS | >48 | >65 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| FERPA violation (student data) | Low | Critical | Minimize data collected; no student social logins for under-13; privacy counsel review in M1 |\n| Teachers won’t pay personally; need school budget | Medium | High | Price at $12–15 to stay below “personal purchase” threshold; build school plan for institutional sales |\n| Google Classroom API throttling | Medium | Medium | Cache assignment data; respect rate limits; provide manual entry as permanent fallback |\n| Low parent email engagement (digest ignored) | Medium | Medium | A/B test digest format; add SMS digest option; allow parents to choose frequency |\n| Teacher summer churn (annual contract not renewed) | High | Medium | Offer annual plan at discount; “summer hold” option that pauses billing but retains data |\n| Competition from Google adding better completion analytics | Medium | Medium | Focus on parent communication and early-warning alerts as differentiated value |',
 E'[{"step": 1, "action": "Problem validation", "rationale": "Surveyed 18 K-8 teachers; 14 said manual homework tracking was a top-3 weekly time waster. Parent communication was the secondary pain."}, {"step": 2, "action": "Competitive mapping", "rationale": "Google Classroom and Seesaw dominate but neither does automated parent digests or completion analytics. The gap is clear."}, {"step": 3, "action": "FERPA scoping", "rationale": "Confirmed that tools handling student educational records must comply with FERPA; designed data model to minimize PHI and add parental consent flow."}, {"step": 4, "action": "Pricing research", "rationale": "Teachers pay $12-20/mo out of pocket for tools they love (Boom Cards, Teachers Pay Teachers). $15/mo is within personal budget without school approval."}, {"step": 5, "action": "Go-to-market channel", "rationale": "Teacher Facebook groups and Instagram (#teacherspayteachers community) are highest-ROI acquisition channels; PLG via class invite codes spreads within schools."}, {"step": 6, "action": "Feature prioritization", "rationale": "Parent digest is the killer feature that differentiates ClassPulse from free tools; prioritized for M2 so it’s in place before word-of-mouth starts."}]',
 'submitted', 31,
 NOW() - INTERVAL '25 days', NOW() - INTERVAL '25 days', NOW() - INTERVAL '25 days');

