INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(13, 3, E'# PolishBook — Nail Art Portfolio & Appointment Platform\n\n## 1. Executive Summary\n\nPolishBook is an all-in-one nail salon platform that replaces the Instagram-screenshot consultation with a browsable, searchable design portfolio. Clients browse hundreds of nail art designs, save favorites to a wishlist, and book directly with their preferred technician including their chosen design. On the salon side, each technician maintains her own branded portfolio; the front desk gets a booking dashboard showing which designs are requested (so they can prep supplies and time slots accurately). The result is a 60–80% reduction in pre-appointment back-and-forth and a measurable increase in client satisfaction scores. Built for nail salons with 3–8 technicians where each technician has a distinct style and client following.\n\n**Year-1 Goals**:\n- 400 salon subscriptions\n- Average 55% reduction in consultation time per appointment\n- MRR of $52,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Nail salons in the US | ~56,000 | NAILS Magazine 2023 |\n| Salons with 3–8 technicians | ~18,000 | Estimated 32% of total |\n| Average appointment value | $45–$95 | Service menu benchmarks |\n| Avg pre-consultation time (currently) | 10–20 min | Salon owner interviews |\n| Revenue lost to consultation overruns | $15–22/appointment | Time x hourly rate |\n| Salons using dedicated booking software | ~58% | NAILS Mag survey |\n| Salons with a digital design portfolio | <14% | Proprietary survey N=120 |\n| Instagram as primary design reference | 74% of clients | Client survey |\n| TAM (nail salon SaaS) | ~$216M/year | 18,000 × $1,000/yr |\n| Year-1 SOM | ~$624K | 400 × $130/mo |\n\n## 3. Competitive Landscape\n\n| Product | Design Portfolio | Booking | Technician Profiles | Price/mo | Weakness |\n|---------|-----------------|---------|---------------------|----------|----------|\n| Vagaro | No | Yes | Basic | $25–85 | Generic beauty booking; no design portfolio |\n| Square Appointments | No | Yes | No | $29–69 | No nail-specific features |\n| Booksy | No | Yes | Basic | $29–49 | No portfolio, no design pre-selection |\n| GlossGenius | Limited (photos) | Yes | Basic | $24–48 | Solo-focused; no multi-tech team view |\n| Pinterest / Instagram | Yes (informal) | No | No | Free | No booking, no organization, no salon control |\n| **PolishBook** | **Yes (core feature)** | **Yes (integrated)** | **Yes (per-tech)** | **$89–$149** | **New brand** |\n\n## 4. Target User Personas\n\n### Persona A: Boutique Salon Owner — Ashley Tran\n- **Age**: 34, owns a 5-technician nail salon in suburban Texas\n- **Current System**: Vagaro for booking; technicians post on their personal Instagram accounts\n- **Pain Points**:\n  1. Clients show up with a saved Instagram screenshot but it’s a different technician’s work; awkward conversation follows\n  2. Consultations eat 15 min per client, killing throughput during peak hours\n  3. New clients don’t know which technician is best for the style they want\n- **Goal**: Clients arrive knowing exactly what they want and who should do it; prep time cut in half\n- **WTP**: $99–$129/month; frames it as recovering 2 appointment slots per day\n\n### Persona B: Top Nail Artist — Keisha Williams\n- **Age**: 27, lead technician at an upscale salon in Atlanta, 6-year client book\n- **Pain Points**:\n  1. Clients book with her because of her Instagram, but the salon has no way to showcase her specific portfolio during booking\n  2. She wastes time on consultations for styles she’s not known for because clients pick her by availability, not skill\n  3. Wants to attract her ideal clients: intricate nail art, $80+ tickets\n- **Goal**: Her personal portfolio visible at booking so only the right clients book her\n- **WTP**: Zero (employer pays); advocates strongly for tool that helps her business\n\n### Persona C: Hands-On Client — Priya Mehta\n- **Age**: 29, regular nail client in Seattle, books every 3 weeks\n- **Pain Points**:\n  1. Spends 20+ minutes the night before an appointment scrolling Pinterest and Instagram to find a reference\n  2. Technician sometimes says “I don’t do that style” after she’s already booked\n  3. Wants to save designs she loves across multiple appointments\n- **Goal**: One place to browse her salon’s actual portfolio, save favorites, and book with the right technician\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Technician design portfolio (photo gallery) | P0 | Each technician uploads and tags their work (style, color, technique, time required) |\n| Client design browsing + wishlist | P0 | Client-facing gallery with filter by style, color, length, technician |\n| Design-linked appointment booking | P0 | Client selects design before or during booking; design attached to appointment |\n| Booking dashboard with design preview | P0 | Front desk sees upcoming appointments with the requested design |\n| Design tags (style, color, nail shape, duration) | P1 | Searchable metadata; auto-estimates appointment length by design complexity |\n| Client profile with design history | P1 | “Your past looks” + saved wishlist |\n| Technician specialty matching | P1 | Routing logic: recommend technician based on design style match |\n| Online booking widget (embeddable) | P1 | Embed on salon website or Google Business Profile |\n| Appointment reminders (SMS/email) | P2 | Standard 24-hr reminder with design preview image attached |\n| Supply prep notifications | P2 | Alert front desk when specific gel colors/nail art supplies needed for booked design |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. Redis for session and queue. S3 (or Cloudflare R2) for image storage with CDN delivery.\n\n**Image Pipeline**: Upload ‒ resize/compress (Sharp) ‒ store in R2 ‒ serve via CDN. Auto-generate thumbnail and full-res versions. Target <200KB per gallery image for mobile performance.\n\n**Client Booking Flow**: Guest flow (no account required for basic booking). Optional account creation to save wishlist and booking history. Magic link login (no password required).\n\n**Frontend**: Next.js 15 + TailwindCSS 4. Portfolio gallery uses masonry grid (CSS-based, no heavy library). Booking wizard is a 3-step modal: pick design ‒ pick technician ‒ pick time.\n\n**Booking Engine**: Available slot calculation based on service duration + design complexity estimate + technician schedule. Integrates with Google Calendar for technician schedule sync.\n\n**SMS Reminders**: Twilio. Include design thumbnail in MMS where supported. 24-hr and 2-hr reminders configurable by salon.\n\n## 7. Business Model\n\n| Plan | Price/Month | Technicians | Bookings/mo | Features |\n|------|-------------|-------------|-------------|----------|\n| Studio | $89 | Up to 3 | 200 | Portfolio, booking, design-linked appts, reminders |\n| Salon | $129 | Up to 8 | Unlimited | + Technician matching, supply prep alerts, client profiles, analytics |\n| Premium | $179 | Up to 15 | Unlimited | + Custom domain booking page, marketing tools, priority support |\n\n**Additional Revenue**:\n- Onboarding/portfolio setup service: $149 one-time (for salons that want a done-for-you upload)\n- Booking transaction fee (optional model): $0.50/booking instead of subscription\n- SMS overage: $0.015/message above plan cap\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Technician photo upload, portfolio gallery, basic appointment booking (no design link yet), salon admin dashboard |\n| M2 | Weeks 5–8 | Design-linked booking flow, client wishlist, appointment reminders (SMS/email), design tags |\n| M3 | Weeks 9–12 | Technician specialty matching, client profile + history, embeddable booking widget, front desk prep view |\n| M4 | Weeks 13–16 | Supply prep alerts, marketing tools, Stripe billing, analytics dashboard, self-serve onboarding |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active salon subscriptions | 55 | 400 |\n| Avg consultation time reduction | 35% | 55% |\n| Design selection rate at booking | 40% | 65% |\n| MRR | $5,800 | $52,000 |\n| Monthly churn | <6% | <3.5% |\n| Booking widget embed adoption | — | >50% of salons |\n| Client wishlist creation rate | — | >30% of clients |\n| NPS | >45 | >63 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Salon owners unwilling to upload photos (effort) | High | High | Offer done-for-you onboarding service ($149); provide bulk upload tool; launch with 10 demo salons as reference |\n| Technicians resist sharing portfolios through salon | Medium | Medium | Technician keeps rights to her own work; portfolio is her professional asset; position as career-building tool |\n| Client adoption of pre-booking design selection low | Medium | Medium | Make it optional (design can be added later); show “clients who pre-selected designs have 40% shorter consultations” |\n| Vagaro / Booksy adds photo portfolio feature | Medium | Medium | Nail art portfolio requires nail-specific UX (masonry, style tags, technique metadata) that generic booking tools won’t invest in |\n| Image storage costs at scale | Low | Medium | Use Cloudflare R2 (zero egress fees); compress aggressively; cap free storage at 500 images, $10/mo add-on beyond |\n| Seasonal demand (spring/summer peak, January slow) | Low | Low | Annual billing option; winter promotion for new salon onboarding |',
 E'[{"step": 1, "action": "Problem observation", "rationale": "Visited 6 nail salons; in every case clients showed Instagram screenshots during consultation. This is a broken UX that burns 10-20 min per appointment."}, {"step": 2, "action": "Competitive analysis", "rationale": "Every existing booking tool (Vagaro, Booksy, GlossGenius) focuses on scheduling but treats photos as an afterthought. Zero tools do design-linked booking. Clear gap."}, {"step": 3, "action": "Image infrastructure design", "rationale": "Gallery performance is critical for adoption. Chose Cloudflare R2 + CDN for zero-egress cost and fast global delivery; masonry CSS grid over JS for mobile speed."}, {"step": 4, "action": "Three-user flow mapping", "rationale": "Mapped the booking flow for all three users (owner, technician, client) to ensure the design-selection step adds convenience rather than friction."}, {"step": 5, "action": "Pricing anchoring", "rationale": "Anchored Salon plan at $129/mo by calculating recovered revenue: cutting 15 min per client × 8 clients/day × $1.50/min = $180/day recovered. $129/mo ROI is instant."}, {"step": 6, "action": "Onboarding risk mitigation", "rationale": "The done-for-you portfolio upload service ($149) is a critical risk mitigation: it removes the biggest adoption barrier (effort to upload 100+ photos) while generating setup revenue."}]',
 'submitted', 48,
 NOW() - INTERVAL '30 days', NOW() - INTERVAL '30 days', NOW() - INTERVAL '30 days');

