INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(13, 10, E'# NailCanvas — Visual Menu & Booking for Nail Technician Teams\n\n## 1. Executive Summary\n\nNailCanvas reimagines the nail salon service menu as a visual experience. Instead of a text-based service list, clients see a scrollable visual menu where each “item” is a real photo of finished nails with price, time estimate, and the technician who specializes in it. Clients build a “nail order” (design + add-ons + technician preference) the same way they order from a visual restaurant menu on DoorDash. The salon gets accurate appointment duration estimates (auto-calculated from design complexity), a prep list for each booking, and a reduction in last-minute client changes that cause schedule overruns.\n\n**Core Metaphor**: A visual menu, not a portfolio. Clients don’t browse an artist’s gallery; they order from a curated menu where every item has a price and a time.\n\n**Year-1 Goals**:\n- 350 salon subscriptions\n- Average booking accuracy improvement (actual vs. estimated time): from 68% to 88%\n- MRR of $44,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| US nail salons | ~56,000 | NAILS Magazine 2023 |\n| Salons with 3–8 technicians (target) | ~18,000 | Industry estimate |\n| Avg revenue lost to schedule overruns | $200–$600/week | Salon owner interviews |\n| % of appointments that run over schedule | 31% | Mystery shopper audit |\n| Main cause of overruns | Design change at checkout (58%) | Same audit |\n| Salons with visual digital menu | <8% | Proprietary survey |\n| Average ticket per appointment | $55–$90 | Service benchmarks |\n| TAM | ~$216M/year | 18,000 × $1,000/yr |\n| Year-1 SOM | ~$528K | 350 × $126/mo |\n\n## 3. Competitive Landscape\n\n| Product | Visual Menu | Duration Estimate | Add-on Upsell | Price/mo | Nail Focus |\n|---------|------------|-------------------|---------------|----------|------------|\n| Vagaro | No | Manual | Limited | $25–85 | No |\n| GlossGenius | Photo gallery | No | Basic | $24–48 | Partial |\n| Booksy | No | Manual | Limited | $29–49 | No |\n| Fresha | No | Manual | Yes | Free + fees | No |\n| MindBody | No | Manual | Yes | $129–$349 | No (wellness focus) |\n| **NailCanvas** | **Yes (core)** | **Auto (by design)** | **Yes** | **$99–$149** | **Yes** |\n\n## 4. Target User Personas\n\n### Persona A: Schedule-Obsessed Salon Owner — Jessica Park\n- **Age**: 41, owns a 6-technician nail salon in suburban New Jersey\n- **Pain Points**:\n  1. 30–40% of appointments run over because the client changes her mind on the design at the chair\n  2. No way to enforce accurate appointment durations—booking software has one duration for “manicure” regardless of design complexity\n  3. Scheduling overruns cause cascading delays; clients wait 20+ min past their time\n- **Goal**: Clients commit to a design and accurate time slot before they arrive\n- **WTP**: $119–$149/month; calculates recovering 2 appointment slots per technician per day = $480+/day\n\n### Persona B: Trendy Nail Technician — Destiny Okafor\n- **Age**: 24, nail technician in a high-volume Atlanta salon, 3 years experience\n- **Pain Points**:\n  1. Clients book a standard manicure then request a 2-hour nail art design\n  2. She can’t say no, so she runs late and the next client is upset\n  3. Her specialty (intricate gel art, $80+ tickets) is buried in the generic service menu\n- **Goal**: Her nail art designs have their own menu items with accurate pricing and duration so she only gets booked for work she’s actually paid for\n\n### Persona C: Upscale Nail Client — Cassandra Mills\n- **Age**: 33, marketing director in Chicago, books nail appointments every 3 weeks\n- **Pain Points**:\n  1. Hates arriving with a vague idea and spending 15 min in a consultation before the work starts\n  2. Wants to see actual prices for designs, not “call for pricing”\n  3. Has been upsold aggressively during consultations; wants to decide pricing upfront\n- **Goal**: Know exactly what she’s getting and what she’s paying before she books\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Visual menu builder (design + price + duration + technician) | P0 | Drag-and-drop menu item creation with photo upload |\n| Duration auto-estimation by design complexity | P0 | Simple (30 min) / Moderate (60 min) / Complex (90+ min) tagging |\n| Client visual ordering flow | P0 | Client builds their “nail order”: base design + add-ons + technician + time |\n| Locked booking (design committed) | P0 | Client can only change design 24+ hrs before; change fee option for salon |\n| Prep checklist per appointment | P0 | Front desk / technician sees required polishes, tools, estimated duration |\n| Technician specialty tags | P1 | Each menu item linked to technician(s) who offer it |\n| Add-on upsell prompts | P1 | During booking: “Add nail art to any finger +$12”; “Upgrade to gel +$15” |\n| Schedule view with duration accuracy tracking | P1 | Color-coded slots; tracks actual vs. estimated duration over time |\n| Client rebooking with same design | P2 | One-tap rebook with the same design from last visit |\n| Post-appointment photo capture | P2 | Technician photos the finished work; auto-added to menu gallery |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. S3-compatible image storage (Cloudflare R2).\n\n**Menu Builder**: Admin web app with drag-and-drop grid (React DnD). Each menu item stores: photos (up to 8), description, base price, add-on list, complexity tag, technician IDs, is_active.\n\n**Duration Engine**: Complexity tag ‒ duration range lookup. If client selects multiple services, sum durations with a buffer. Slot availability filtered by duration at booking time.\n\n**Locked Booking**: After booking confirmation, design and duration are locked. Change requires >24h notice or triggers configurable change fee. Change fee charged automatically via Stripe.\n\n**Client Flow**: PWA (Progressive Web App) optimized for mobile. No app install required. Magic-link authentication for returning clients. Guest checkout for first-timers.\n\n**Schedule View**: Calendar grid with per-technician columns. Duration accuracy calculated post-appointment: when technician marks complete, actual end time recorded. Weekly accuracy report emailed to salon owner.\n\n## 7. Business Model\n\n| Plan | Price/Month | Technicians | Key Features |\n|------|-------------|-------------|------|\n| Studio | $99 | Up to 3 | Visual menu, locked booking, prep checklist, SMS reminders |\n| Salon | $139 | Up to 8 | + Add-on upsells, duration tracking, schedule analytics |\n| Pro | $179 | Up to 15 | + Custom domain, marketing tools, post-visit photo capture, API |\n\n**Transaction Model (alternative to subscription)**: 2.5% per booking for salons preferring no monthly fee. Typically more expensive than subscription above $40K annual revenue.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Menu builder (photo + price + duration), basic appointment booking, technician assignment |\n| M2 | Weeks 5–8 | Locked booking with change policy, prep checklist, client mobile PWA, SMS reminders |\n| M3 | Weeks 9–12 | Add-on upsell flow, schedule duration tracking, technician specialty matching, change fee (Stripe) |\n| M4 | Weeks 13–16 | Duration accuracy reporting, rebooking, post-visit photo capture, self-serve onboarding |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active salon subscriptions | 45 | 350 |\n| Booking duration accuracy rate | 75% | 88% |\n| Design commitment rate (clients commit before arrival) | 50% | 70% |\n| MRR | $4,200 | $44,000 |\n| Monthly churn | <7% | <4% |\n| Add-on upsell attach rate | — | >22% |\n| NPS | >42 | >61 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Salon owners resist locking bookings (fear of losing clients) | Medium | High | Frame locked booking as client convenience (they know exactly what to expect); A/B test with soft lock (no penalty) first |\n| Photo upload quality is poor (blurry/bad lighting) | High | Medium | Provide in-app photo tips; offer free photography guide; flag low-quality images with improvement prompts |\n| Duration estimates are inaccurate initially | High | Medium | Seed with industry-standard time data; allow salon to override per technician; learn from actual vs. estimated over 30 days |\n| Clients resist committing to a design in advance | Medium | Medium | Allow “I’ll decide at the salon” option for standard services; design selection required only for complex nail art |\n| Fresha offers visual menu (free + transaction fee) | Medium | High | Compete on nail-specific features (complexity estimation, prep checklist, technician specialty) that a horizontal tool won’t build |\n| Low-margin salons cannot afford subscription | Medium | Medium | Offer transaction-fee model (2.5%) as alternative for price-sensitive salons |',
 E'[{"step": 1, "action": "Core metaphor definition", "rationale": "Reframed the product as a ''visual menu'' not a portfolio. A menu has prices and durations attached; a portfolio is just pictures. The menu framing solves the schedule accuracy problem."}, {"step": 2, "action": "Schedule overrun research", "rationale": "Conducted mystery shopper audit at 12 salons; found 31% of appointments ran over, 58% due to last-minute design changes. This is the core revenue leak to solve."}, {"step": 3, "action": "Locked booking policy design", "rationale": "Deliberated on how strict to make the design commitment. Settled on 24-hour change window with optional change fee, giving salons control without scaring off clients."}, {"step": 4, "action": "Duration auto-estimation", "rationale": "Simple/Moderate/Complex tagging by technician is the practical MVP. Full ML-based estimation would be over-engineered for V1 and requires training data the product doesn’t have yet."}, {"step": 5, "action": "Competitive positioning", "rationale": "Fresha is the most dangerous competitor (free). Differentiation is nail-specific depth: prep checklist, complexity estimation, technician specialty routing. A horizontal tool won’t build these."}, {"step": 6, "action": "Pricing decision", "rationale": "Set $139 Salon plan by comparing to Vagaro ($85) + Instagram (free portfolio). The $54 premium is justified if it eliminates 2 schedule overruns per week (worth $400+)."}]',
 'submitted', 40,
 NOW() - INTERVAL '23 days', NOW() - INTERVAL '23 days', NOW() - INTERVAL '23 days');

