INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(13, 27, E'# GelGallery — Nail Technician Portfolio Network & Social Booking\n\n## 1. Executive Summary\n\nGelGallery combines a technician-owned portfolio with a local discovery layer, turning individual nail artists into a bookable network. Each technician gets her own branded mini-site (gelgallery.com/keisha) with a scrollable portfolio, style tags, pricing, and a booking calendar. Clients can discover technicians by style or location, follow favorite artists, and save designs to a board for their next appointment. The salon owner sees all her team’s portfolios under one roof, manages team-wide scheduling, and tracks which technician’s style is driving the most new client bookings. GelGallery is designed for nail salons where individual technician reputation drives referrals but there’s no unified platform to leverage it.\n\n**Differentiation**: GelGallery gives nail technicians something Instagram can’t: a profile that converts visitors directly into bookings, with a salon-side dashboard to manage the team.\n\n**Year-1 Goals**:\n- 500 salon subscriptions (1,800+ individual technician profiles)\n- 25% of new client bookings attributed to GelGallery discovery\n- MRR of $62,500 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| US nail salons | ~56,000 | NAILS Magazine 2023 |\n| Nail technicians (employed) | ~380,000 | BLS 2023 |\n| Avg technicians per target salon (3–8) | 5.2 | Industry estimate |\n| Target salons (3–8 technicians) | ~18,000 | 32% of total |\n| % of clients who book based on seeing a technician’s specific work | 63% | Client survey N=280 |\n| % of technicians with Instagram portfolios | 71% | Observation survey |\n| % who convert Instagram followers to bookings directly | 18% | Same survey (low due to friction) |\n| New client acquisition cost via word-of-mouth | $0 | But limited reach |\n| TAM | ~$216M/year | 18,000 salons × $1,000/yr |\n| Year-1 SOM | ~$750K | 500 × $125/mo |\n\n## 3. Competitive Landscape\n\n| Product | Technician Portfolio | Discovery/SEO | Direct Booking | Social Follow | Price/mo |\n|---------|---------------------|---------------|----------------|---------------|----------|\n| Instagram | Yes (informal) | Partial (hashtag) | No (link in bio) | Yes | Free |\n| Vagaro Marketplace | Limited | Yes | Yes | No | $25–85 |\n| Booksy Marketplace | No | Yes | Yes | No | $29–49 |\n| StyleSeat | Limited | Yes | Yes | No | 25–35% commission |\n| GlossGenius | Basic photos | No (no marketplace) | Yes | No | $24–48 |\n| **GelGallery** | **Yes (core, branded)** | **Yes (SEO + local)** | **Yes** | **Yes** | **$99–$149** |\n\n## 4. Target User Personas\n\n### Persona A: Ambitious Nail Artist Building Her Brand — Monique Hayes\n- **Age**: 26, nail technician at a 5-person salon in Houston, 4 years experience\n- **Current Situation**: 4,200 Instagram followers; ~20% of her clients found her via Instagram\n- **Pain Points**:\n  1. Instagram followers can’t book directly; they DM her and the conversation goes in circles\n  2. Her Instagram is mixed: nail work + personal posts; not professional enough for some clients\n  3. She has no metrics: doesn’t know which designs drive the most bookings\n- **Goal**: A professional portfolio that converts followers into booked appointments; analytics on what’s working\n- **WTP**: Free if salon pays; would pay $20/mo personally if salon doesn’t\n\n### Persona B: Salon Owner Managing Team Growth — Linda Reyes\n- **Age**: 47, owns a 7-technician salon in Miami, 12 years in business\n- **Pain Points**:\n  1. Three of her technicians have strong Instagram followings; bookings for them are full. The other four have none and are underbooked.\n  2. No unified way to promote all technicians’ work under the salon brand\n  3. New clients who find the salon on Google see no visual portfolio; they don’t know what they’re getting\n- **Goal**: Unified team showcase that drives new client discovery and fills underbooked technicians\n- **WTP**: $119–$149/month for team plan\n\n### Persona C: Design-Savvy New Client — Sophia Reeves\n- **Age**: 25, moved to a new city 3 months ago, looking for a nail salon\n- **Current Process**: Google “nail salons near me” ‒ reads Yelp reviews ‒ visits Instagram ‒ tries to book\n- **Pain Points**:\n  1. Can’t find a technician whose specific style she loves and book them in one place\n  2. Yelp reviews don’t show design style; just “good prices” and “clean salon”\n  3. Wants to follow a technician and be notified when she has openings\n- **Goal**: Find a local nail artist whose style matches hers and book in one click\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Technician mini-site (gelgallery.com/name) | P0 | Branded portfolio page with photos, bio, style tags, prices, booking calendar |\n| Salon team hub (gelgallery.com/salon-name) | P0 | All technicians displayed under salon brand; salon owner managed |\n| Style-tagged photo upload | P0 | Tag each photo: style (minimalist, 3D art, ombre, etc.), color, season, nail length |\n| Direct booking from portfolio | P0 | Client books with specific technician from their profile page |\n| Client “save” and follow technicians | P1 | Wishlist of saved designs; follow artist for opening notifications |\n| Discovery + local search | P1 | Search by city + style; SEO-optimized technician pages |\n| Opening notifications | P1 | Clients who follow a technician get SMS/email when she adds availability |\n| Booking analytics per technician | P1 | Which designs drive most bookings; follower growth; conversion rate |\n| Appointment reminder (SMS/email) | P2 | Standard 24-hr reminder with design preview |\n| Review display (Google import) | P2 | Pull Google reviews and display on technician page |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. Cloudflare R2 for photo storage. Redis for follower notification queues.\n\n**SEO Architecture**: Each technician page is a Next.js static page (ISR, regenerated on portfolio update). URL structure: gelgallery.com/[city]/[name]. Schema markup for local business and creative work. Goal: rank for “nail artist [city] [style]” searches.\n\n**Discovery Engine**: Geolocation (IP-based or browser geolocation) + style filter. Results sorted by: follower count, recent activity, availability in next 7 days.\n\n**Follow + Notification System**: Redis pub/sub for real-time slot notifications. When technician adds availability block, worker fans out SMS/email to all followers. SendGrid + Twilio.\n\n**Booking Engine**: Per-technician availability calendar (15-min slots). Client books slot; confirmation sent; salon dashboard updated. Google Calendar export for technician personal use.\n\n**Analytics**: Server-side events (no third-party trackers on public portfolio pages). Per-design CTR (saves), per-portfolio conversion rate, follower growth chart. Weekly email digest to technician.\n\n## 7. Business Model\n\n| Plan | Price/Month | Technicians | Features |\n|------|-------------|-------------|----------|\n| Solo Artist | $29 | 1 | Technician mini-site, booking, portfolio, basic analytics |\n| Salon Team | $119 | Up to 8 | + Salon hub, team analytics, opening notifications, Google review import |\n| Salon Pro | $159 | Up to 15 | + Priority discovery placement, custom domain, marketing tools |\n\n**Marketplace Model (alternative)**: Free listing + 8% commission per booking. Estimated equivalent to ~$99/mo at average volume. Salons can switch to subscription when monthly bookings exceed threshold.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Technician mini-site, photo upload + style tags, basic booking flow, salon team hub |\n| M2 | Weeks 5–8 | Client save/follow, opening notifications (email), discovery search (city + style), SEO pages |\n| M3 | Weeks 9–12 | SMS notifications, booking analytics, Google review import, appointment reminders |\n| M4 | Weeks 13–16 | Stripe billing (both models), self-serve onboarding, referral program, marketing tools |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active salon subscriptions | 65 | 500 |\n| Technician profiles created | 250 | 1,800 |\n| Discovery-attributed bookings (% of total) | 12% | 25% |\n| MRR | $7,200 | $62,500 |\n| Monthly churn | <6% | <3.5% |\n| Client follow / save rate | — | >35% of unique visitors |\n| NPS | >44 | >65 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Technicians build personal following and leave salon | Medium | Medium | Portfolio belongs to technician (portable); frame as an asset she owns. Salon benefits from team’s collective draw. |\n| Discovery/SEO takes 6–12 months to rank | High | Medium | Launch with paid social ads targeting nail clients by city; SEO is medium-term, not launch strategy |\n| Commission model creates booking conflicts (salon vs. marketplace) | Medium | High | Subscription model preferred; commission offered only for salons that explicitly opt-in as a trial |\n| Instagram already does this (for free) | High | Medium | GelGallery converts; Instagram doesn’t. Bookings from Instagram require DM ‒ back-and-forth ‒ Venmo. GelGallery is one click. |\n| Photo content quality varies widely | Medium | Medium | Offer style guide and photography tips at onboarding; allow salon owner to approve photos before they go live |\n| StyleSeat or Booksy adds portfolio + discovery | Low | High | Build technician loyalty via owned profiles (portable URL); switching cost is losing followers and SEO history |',
 E'[{"step": 1, "action": "Network effect design", "rationale": "Decided to build a discovery layer (not just a booking tool) to create network effects: more technicians ‒ better discovery ‒ more clients ‒ more technicians want to be listed."}, {"step": 2, "action": "Instagram comparison", "rationale": "Instagram is the incumbent but converts poorly. The key insight: the booking funnel (DM ‒ negotiate ‒ Venmo) is broken. GelGallery replaces that funnel with a single click."}, {"step": 3, "action": "SEO architecture planning", "rationale": "Nail art + city + style is an underserved search intent. Static ISR pages for each technician profile can rank for ''[style] nail artist [city]'' queries with zero ad spend long-term."}, {"step": 4, "action": "Dual model decision (subscription vs. commission)", "rationale": "Commission is familiar from StyleSeat but creates friction and misaligned incentives. Subscription preferred; commission offered as opt-in to attract zero-upfront-cost sensitive salons."}, {"step": 5, "action": "Technician ownership model", "rationale": "Debated who owns the portfolio (salon vs. technician). Decided technician owns it (portable URL) because this drives technician advocacy and salon adoption. Salon benefits from aggregation."}, {"step": 6, "action": "Pricing structure", "rationale": "Solo Artist at $29 enables individual technicians to sign up even if their salon doesn’t. This seeds content in a market before the full salon pitch; individual signups become proof of concept for salon conversations."}]',
 'submitted', 33,
 NOW() - INTERVAL '17 days', NOW() - INTERVAL '17 days', NOW() - INTERVAL '17 days');

