INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(14, 5, E'# PolicyPulse — Client Relationship & Renewal Engine for Independent Insurance Agents\n\n## 1. Executive Summary\n\nPolicyPulse is a CRM purpose-built for independent insurance agents managing 200–500 clients. It automates the three activities that drive agent revenue: policy renewal reminders, scheduled client check-ins, and referral tracking. Most independent agents manage client relationships in a mix of spreadsheets, calendar reminders, and their carrier’s back-end portal—none of which were designed for proactive relationship management. PolicyPulse centralizes all client touchpoints, sends automated multi-channel renewal sequences starting 90 days out, and surfaces which clients are most likely to lapse or be cross-sell candidates. The result: agents retain more policies, write more cross-sells, and generate more referrals from a satisfied book of business.\n\n**Core Value Proposition**: Never let a policy lapse because you forgot to call. Never miss a referral because you forgot to ask.\n\n**Year-1 Goals**:\n- 600 active agent subscriptions\n- Average policy retention improvement: +12 percentage points\n- MRR of $90,000 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Independent insurance agents (US) | ~360,000 | IIABA 2023 |\n| Agents with 200–500 clients (target) | ~108,000 | Estimated 30% of total |\n| Average annual premium per client | $1,800–$3,200 | Personal + auto mix |\n| Agent commission rate (renewal) | 8–12% | Industry avg |\n| Annual revenue lost to preventable lapses | $8K–$22K/agent | At 3–5% lapse rate |\n| Agents using dedicated relationship mgmt tools | <28% | LIMRA 2023 survey |\n| Agents spending >4 hrs/week on manual follow-up | 58% | Proprietary survey N=180 |\n| TAM (insurance agent CRM SaaS) | ~$648M/year | 108,000 × $500/yr |\n| SAM | ~$194M/year | 30% reachable |\n| Year-1 SOM | ~$1.08M | 600 × $150/mo |\n\n## 3. Competitive Landscape\n\n| Product | Insurance-Specific | Renewal Automation | Referral Tracking | Check-in Scheduling | Price/mo |\n|---------|-------------------|---------------------|-------------------|---------------------|----------|\n| Salesforce Financial Services | Partial | No | No | No | $225–$300+ |\n| HubSpot CRM | No | Sequences only | No | Manual | $50–$800 |\n| AgencyZoom | Yes | Yes | Partial | No | $99–$249 |\n| HawkSoft | Yes (agency mgmt) | Basic | No | No | $200–$400 |\n| NowCerts | Yes (agency mgmt) | Basic | No | No | $79–$159 |\n| **PolicyPulse** | **Yes** | **Advanced (90-day seq.)** | **Yes** | **Automated** | **$99–$179** |\n\n## 4. Target User Personas\n\n### Persona A: Established Independent Agent — Tom Callahan\n- **Age**: 52, independent P&C agent in Ohio, 380 clients, 18 years in business\n- **Current System**: Spreadsheet for renewals; paper sticky notes for follow-up calls; carrier portals for policy data\n- **Pain Points**:\n  1. Lost 3 clients last year to policy lapses he didn’t catch in time\n  2. Spends 5 hours/week manually tracking who needs a call; still misses people\n  3. Knows he should ask for referrals but forgets in the middle of service calls\n- **Goal**: A system that tells him who to call each morning and sends renewal reminders automatically\n- **WTP**: $129–$149/month; calculates that retaining 2 extra policies per year pays for 3 years of subscription\n\n### Persona B: Growing Young Agent — Brittany Odom\n- **Age**: 31, independent life + health agent in Georgia, 210 clients, 4 years in business\n- **Pain Points**:\n  1. Growing fast but her follow-up system can’t scale with her book\n  2. Cross-sell opportunities slip through the cracks (client has auto with her but she never pitched homeowners)\n  3. Referrals are her primary growth channel but she has no system to track who referred whom\n- **Goal**: Automated check-in sequences so she can focus on new business, not managing existing clients manually\n- **WTP**: $99–$119/month; views it as enabling growth not just maintenance\n\n### Persona C: Multi-Line Agent Transitioning from Captive — David Park\n- **Age**: 44, recently went independent after 15 years at State Farm, 290 clients\n- **Pain Points**:\n  1. Lost his carrier CRM system when he went independent\n  2. Rebuilding client relationships from scratch; needs to show clients he remembers them\n  3. No referral tracking; doesn’t know which clients send the most new business\n- **Goal**: A CRM that feels professional and makes clients feel valued, not just transacted\n- **WTP**: $129–$159/month\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Client + policy record management | P0 | Per-client: policies, renewal dates, contact info, notes, relationship score |\n| 90-day renewal reminder sequence | P0 | Auto multi-touch: email at 90 days, SMS at 60 days, call prompt at 30 days, final notice at 14 days |\n| Daily action list (who to call today) | P0 | Prioritized list: renewals due, overdue check-ins, referred clients to thank |\n| Annual check-in scheduler | P0 | Each client gets a scheduled annual review; auto-reminder to agent and client |\n| Referral tracking | P0 | Log who referred whom; referral thank-you sequence; top referrer leaderboard |\n| Cross-sell opportunity flags | P1 | Flag clients who have auto but no home; life but no disability; etc. |\n| Carrier portal data import | P1 | CSV import from major carriers (Nationwide, Travelers, Progressive); auto-populate renewal dates |\n| Client communication log | P1 | Log every call, email, text; searchable history per client |\n| Birthday and life event reminders | P2 | Auto-surface on client anniversary, birthday for personal touch outreach |\n| Agency-wide dashboard (for small teams) | P2 | Principal agent sees team-wide renewal pipeline and check-in status |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. Redis for job queue (sequence trigger engine).\n\n**Renewal Sequence Engine**: Cron-based trigger: daily job scans all policies for renewal date milestones. Queues appropriate action (email, SMS, call prompt) per client. Deduplicates if action already taken.\n\n**Communications**: Twilio (SMS), SendGrid (email). Agent receives call prompts as in-app tasks + optional SMS to agent’s own phone. Client-facing emails are from agent’s email (SMTP relay via SendGrid) so they appear personal.\n\n**Carrier Import**: CSV/Excel upload with field mapping UI. Supports Nationwide, Travelers, Progressive, Allstate standard export formats. Manual override for any carrier with custom format.\n\n**Frontend**: Next.js 15 + TailwindCSS 4. Dashboard: daily action list (top of page), renewal pipeline (kanban by stage), client search. Mobile responsive.\n\n**Data Security**: SOC 2 Type II target Q4. Client PII encrypted at rest. Agent data isolated per account (no cross-tenant access). E&O insurance coverage document storage (S3, encrypted).\n\n## 7. Business Model\n\n| Plan | Price/Month | Clients | Features |\n|------|-------------|---------|----------|\n| Solo | $99 | Up to 250 | Renewal sequences, check-ins, referral tracking, daily action list |\n| Professional | $149 | Up to 500 | + Cross-sell flags, carrier import, communication log, team up to 2 agents |\n| Agency | $229 | Unlimited | + Agency dashboard, unlimited team, priority support, API access |\n\n**Annual discount**: 15% (saves ~$270–$410/year; improves cash flow and reduces churn).\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Client + policy records, renewal date tracking, daily action list, basic reminder emails |\n| M2 | Weeks 5–8 | Full 90-day renewal sequence (email + SMS + call prompt), referral logging, annual check-in scheduler |\n| M3 | Weeks 9–12 | Carrier CSV import, cross-sell opportunity flags, communication log, referral thank-you sequences |\n| M4 | Weeks 13–16 | Agency dashboard, birthday reminders, Stripe billing, self-serve onboarding, integration with AgencyZoom export |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active agent subscriptions | 80 | 600 |\n| Avg policy renewal improvement | +7 ppts | +12 ppts |\n| MRR | $9,200 | $90,000 |\n| Monthly churn | <6% | <3.5% |\n| Daily action list engagement rate | >60% | >75% |\n| Referral tracking adoption | — | >55% of agents |\n| NPS | >50 | >68 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Agents resist entering client data (migration effort) | High | High | Offer free data migration service for annual subscribers; build CSV import from common sources |\n| Carrier API restrictions limit data sync | Medium | Medium | CSV import is always available; carrier API partnerships targeted for Y2 |\n| AgencyZoom expands feature set at same price | Medium | High | Focus on individual agent UX (not agency operations); AgencyZoom targets agencies, not solo agents |\n| E&O liability if agent misses a renewal due to software bug | Low | Critical | Clear terms: tool assists but agent is responsible; mandatory field for agent confirmation before marking renewal “handled” |\n| Low SMS deliverability to clients (carrier spam filters) | Medium | Medium | 10DLC registration, low-volume personalized sends, opt-in at policy inception |\n| Agents churn in slow months (January, August) | Medium | Medium | Annual billing incentive; “Renewal season” onboarding timing (Oct–Nov for Jan renewals) |',
 E'[{"step": 1, "action": "Revenue impact framing", "rationale": "Calculated that a typical agent with 380 clients at 3% lapse rate loses $15K/year in renewal commissions. A $149/mo tool ($1,788/year) that prevents 2-3 lapses pays for itself immediately."}, {"step": 2, "action": "Competitive positioning vs AgencyZoom", "rationale": "AgencyZoom is the closest competitor. It targets agency owners and focuses on agency operations. PolicyPulse targets individual agents and focuses on client relationship quality."}, {"step": 3, "action": "90-day sequence design", "rationale": "Interviewed 14 agents; found the 30-day window is too short for clients to make decisions. 90-day sequences give clients time to shop alternatives and come back; agents who call earlier retain more."}, {"step": 4, "action": "Referral tracking feature addition", "rationale": "7 of 14 interviewed agents said referrals are their #1 growth channel but none tracked them systematically. Adding referral tracking increases retention (agents won’t churn from a tool that shows their referral ROI)."}, {"step": 5, "action": "Daily action list as core UX", "rationale": "Agents don’t want to manage a CRM; they want to be told what to do today. Designed the dashboard around the daily action list, not a record-keeping view."}, {"step": 6, "action": "Pricing and plan structure", "rationale": "Solo at $99 is below the ''needs approval'' threshold for most agents. Professional at $149 targets established agents. Agency at $229 targets small agencies running 2-5 producers."}]',
 'submitted', 47,
 NOW() - INTERVAL '12 days', NOW() - INTERVAL '12 days', NOW() - INTERVAL '12 days');

