INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(15, 8, E'# EngageTrack — Client Engagement & Contract Renewal Management for Accounting Firms\n\n## 1. Executive Summary\n\nEngageTrack is a contract lifecycle management tool purpose-built for small accounting firms with 50–150 business clients. It tracks every client engagement agreement from execution through renewal, sends automated reminders to partners and clients before expiration, and provides a seasonal workload dashboard that helps firms avoid the February–April tax season capacity crunch by identifying which clients need engagement letters renewed before the rush begins. Most small CPA firms manage contracts in a combination of PDF folders, shared drives, and calendar reminders—a system that breaks down when a partner is on vacation or a client’s renewal slips through the cracks. EngageTrack centralizes all engagement data and makes renewal management a proactive, automated workflow.\n\n**Year-1 Goals**:\n- 350 firm subscriptions\n- Zero missed contract renewals in enrolled firms (tracked via partner survey)\n- MRR of $52,500 by month 12\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Small CPA firms in the US (2–10 staff) | ~44,000 | AICPA 2023 |\n| Firms with 50–150 business clients | ~18,000 | Estimated 41% of small firms |\n| Avg annual engagement value per business client | $3,200–8,500 | Tax + bookkeeping mix |\n| Firms with clients whose engagement lapsed unnoticed | 44% | CPA Practice Advisor survey |\n| Revenue lost per lapsed engagement (average) | $4,800 | Engagement avg × client loss |\n| Partners spending >3 hrs/week on contract admin | 52% | Proprietary survey N=140 |\n| Firms using dedicated engagement management tools | <18% | Same survey |\n| TAM | ~$270M/year | 18,000 × $1,250/yr |\n| Year-1 SOM | ~$630K | 350 × $150/mo |\n\n## 3. Competitive Landscape\n\n| Product | CPA-Specific | Contract Tracking | Workload Visibility | Renewal Automation | Price/mo |\n|---------|-------------|-------------------|---------------------|---------------------|----------|\n| Karbon | Yes (workflow) | No | Yes (workflow) | No | $59–$89/user |\n| Canopy | Yes (practice mgmt) | Basic | Partial | No | $50–$75/user |\n| TaxDome | Yes | No | Basic | No | $50/user |\n| DocuSign CLM | No (generic CLM) | Yes | No | Partial | $25–$45/user |\n| Ironclad | No (enterprise) | Yes | No | Yes | $500+/mo |\n| **EngageTrack** | **Yes** | **Yes (core)** | **Yes (seasonal)** | **Yes** | **$99–$169** |\n\n## 4. Target User Personas\n\n### Persona A: Managing Partner of Small CPA Firm — Robert Huang\n- **Age**: 51, managing partner, 4-person firm in suburban Illinois, 85 business clients\n- **Current System**: PDF engagement letters in Dropbox folders; Excel spreadsheet tracking renewal dates; Outlook calendar reminders\n- **Pain Points**:\n  1. A client’s engagement expired unnoticed last March; firm did the work without a signed engagement letter and had a dispute over scope\n  2. Tax season starts without clarity on which client engagements are renewed vs. pending\n  3. Spends 3+ hours/week managing contract admin that he considers non-billable waste\n- **Goal**: Eliminate the risk of unnoticed lapses; arrive at January 1 knowing every engagement status\n- **WTP**: $129–$149/month for the firm; compares to risk of one disputed engagement\n\n### Persona B: Firm Administrator — Carol Jensen\n- **Age**: 44, office manager at a 6-person CPA firm in Ohio, 110 clients\n- **Pain Points**:\n  1. Partners hand her a stack of engagement letters to track; she maintains a spreadsheet but it’s always behind\n  2. Clients sometimes sign and return the wrong version of an updated engagement letter\n  3. Renewal outreach involves emailing each client individually; she drafts 110 emails a year manually\n- **Goal**: System where engagement status is always current and renewal emails go out automatically\n- **WTP**: N/A (firm pays; she is the champion and primary user)\n\n### Persona C: Growth-Oriented Solo CPA — Amanda Reeves\n- **Age**: 36, solo CPA in Texas, 58 business clients, growing toward 100\n- **Pain Points**:\n  1. Currently tracks renewals in a Google Sheet; works now but won’t scale past 80 clients\n  2. Wants to look professional with automated, branded renewal emails rather than manual Gmail drafts\n  3. Needs seasonal workload visibility: which months will be capacity-constrained based on client deliverable schedules\n- **WTP**: $99–$119/month\n\n## 5. Core Features\n\n| Feature | Priority | Description |\n|---------|----------|-------------|\n| Client + engagement contract record | P0 | Per-client: engagement type, start/end date, signed date, value, services in scope |\n| Contract expiration tracking + status | P0 | Status: active / expiring-soon / expired / renewal-pending / renewed |\n| Automated renewal reminder sequences | P0 | 90/60/30/14 days before expiry: email to partner (action prompt) + optional email to client |\n| Seasonal workload dashboard | P0 | Calendar view showing deliverable density by month; capacity warning if >80% of clients expire in same 6-week window |\n| Engagement document storage | P1 | Upload signed PDFs; version history; latest version always accessible |\n| E-signature integration (DocuSign/HelloSign) | P1 | Send renewal engagement letter for signature from within EngageTrack |\n| Bulk renewal workflow | P1 | Generate + send renewal letters for all clients expiring in a given month in one action |\n| Partner assignment + team visibility | P1 | Each engagement assigned to a partner; team dashboard shows all renewals across all partners |\n| Renewal analytics report | P2 | % of renewals completed on time, avg days to renew, clients taking longest to return signed letters |\n| QuickBooks / Xero client sync | P2 | Pull client list from accounting software to pre-populate EngageTrack |\n\n## 6. Technical Architecture\n\n**Backend**: Go 1.22 + Echo v4. PostgreSQL 16. Redis for reminder queue.\n\n**Reminder Engine**: Cron job checks expiration dates nightly. Queues notifications per milestone (90/60/30/14 days). Partner notifications are in-app + email. Client notifications are email only (configurable). Deduplicates to avoid duplicate reminders.\n\n**Document Storage**: AWS S3 with server-side encryption. Version control: each upload creates a new version; previous versions retained for audit trail. Signed URL access (time-limited, per-user).\n\n**E-Signature**: HelloSign API (now Dropbox Sign) for embedded signature requests. Track signature status (sent/viewed/signed/declined). Auto-update engagement status on completion.\n\n**Seasonal Dashboard**: Aggregates engagement end dates by month. Bar chart with color-coded capacity bands (green/yellow/red). Compares current year vs. prior year pattern.\n\n**Frontend**: Next.js 15 + TailwindCSS 4. Primary views: engagement list (sortable by expiry), seasonal dashboard, and client detail page with engagement history.\n\n## 7. Business Model\n\n| Plan | Price/Month | Clients | Team Members | Features |\n|------|-------------|---------|--------------|----------|\n| Solo | $99 | Up to 75 | 1 | Contract tracking, automated reminders, document storage, seasonal dashboard |\n| Firm | $149 | Up to 150 | Up to 5 | + E-signature, bulk renewal, partner assignment, team dashboard |\n| Practice | $219 | Unlimited | Unlimited | + Analytics report, QuickBooks/Xero sync, API access, priority support |\n\n**Annual billing**: 2 months free (~17% discount). Expected 80% of Y2 revenue on annual plans after first renewal cycle.\n\n## 8. MVP Roadmap\n\n| Milestone | Timeline | Deliverables |\n|-----------|----------|--------------|\n| M1 | Weeks 1–4 | Client + engagement records, expiration tracking, status workflow, basic reminder emails (partner-only) |\n| M2 | Weeks 5–8 | Automated client renewal emails, seasonal workload dashboard, document upload (S3), partner assignment |\n| M3 | Weeks 9–12 | HelloSign e-signature integration, bulk renewal workflow, team dashboard view |\n| M4 | Weeks 13–16 | Renewal analytics report, QuickBooks/Xero client sync, Stripe billing, self-serve onboarding |\n\n## 9. Success Metrics\n\n| KPI | M3 Target | M12 Target |\n|-----|-----------|------------|\n| Active firm subscriptions | 45 | 350 |\n| Engagement lapse incidents (enrolled firms) | 0 | 0 |\n| On-time renewal rate | >82% | >92% |\n| MRR | $5,400 | $52,500 |\n| Monthly churn | <5% | <3% |\n| E-signature adoption | — | >60% of Firm plan users |\n| NPS | >55 | >70 |\n\n## 10. Risks & Mitigation\n\n| Risk | Likelihood | Impact | Mitigation |\n|------|------------|--------|------------|\n| Firms resistant to digitizing engagement letters (liability concerns) | Medium | High | Partner with AICPA risk management resources; emphasize that digital tracking reduces liability vs. paper chaos |\n| HelloSign API pricing increases at scale | Low | Medium | Abstract e-signature behind adapter; can swap to DocuSign or PandaDoc |\n| Firm partners don’t log in regularly (low engagement) | Medium | High | Daily email digest is primary UI for partners; app is secondary; design for email-first workflow |\n| QuickBooks/Xero API changes | Low | Low | Client sync is P2 enhancement; manual CSV import always available |\n| Tax season crunch means no time to onboard new tools in Jan–Mar | High | Medium | Target onboarding window: May–August (post-season); trial conversion in September when renewal planning begins |\n| Small firm principal leaves and takes clients (data portability) | Low | Low | Export client data at any time; transparent data ownership in ToS |',
 E'[{"step": 1, "action": "Seasonal workload framing", "rationale": "Identified the accounting firm seasonal crunch (Feb-April) as a unique pain: firms need to know renewal status before January, not in March when it’s too late. Seasonal dashboard addresses this directly."}, {"step": 2, "action": "Competitive gap analysis", "rationale": "Karbon and Canopy are workflow tools; they don’t track contract lifecycle. DocuSign CLM is generic and expensive. Clear gap for a CPA-specific, affordable engagement tracking tool."}, {"step": 3, "action": "E-signature integration scoping", "rationale": "HelloSign (Dropbox Sign) has the best embedded signing UX and lowest per-signature cost. Abstracted behind an adapter to allow swapping. Required for bulk renewal workflow."}, {"step": 4, "action": "Document storage design", "rationale": "Version control is critical: firms need to know which version of an engagement letter a client signed. Designed upload to always create a new version, never overwrite."}, {"step": 5, "action": "Onboarding timing strategy", "rationale": "Tax season (Jan-Apr) is the worst time to onboard. Designed GTM around May-September onboarding window; firms have time to set up and are motivated by ''never again'' after tax season chaos."}, {"step": 6, "action": "Email-first UX design", "rationale": "Partners at small firms don’t check dashboards daily; they check email. Designed daily email digest as the primary interaction surface; the web app is secondary for deeper management."}]',
 'submitted', 58,
 NOW() - INTERVAL '14 days', NOW() - INTERVAL '14 days', NOW() - INTERVAL '14 days');

