INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(17, 2, E'# WeddingOS - The Command Center for Independent Wedding Planners\n\n## 1. Executive Summary\n\nWeddingOS is a purpose-built project management platform for independent wedding planners handling 15-30 weddings per year. Unlike generic project management tools or bloated wedding venue software, WeddingOS is designed around the specific workflow of an independent planner: client onboarding, vendor coordination, timeline management, budget tracking, and day-of execution. The product replaces a patchwork of spreadsheets, Google Docs, and email threads with a single client portal that keeps couples informed and planners in control.\n\n**Core Problem**: Independent wedding planners operate like project managers running 20 simultaneous projects — but they use tools built for single-team collaboration, not multi-client, multi-vendor orchestration.\n\n**Target**: Full-service and partial-planning independent wedding planners in the US, billing $2,500-$8,000 per wedding, handling 15-30 weddings/year.\n\n## 2. Market Analysis\n\n| Metric | Data | Notes |\n|--------|------|-------|\n| US weddings annually | 2.0M | The Knot 2023 |\n| % using a professional planner | ~27% | The Knot |\n| Independent planners (non-franchise) | ~45,000 | WIPA estimate |\n| Avg planner annual revenue | $72,000-$180,000 | 15-30 weddings × avg fee |\n| % using dedicated planning software | ~22% | Internal survey |\n| Top software used | Aisle Planner, Honeybook | Fragmented market |\n| Avg admin hours per wedding | 18-25 hrs | Planner interviews |\n| Admin hours reducible via automation | 30-40% | Estimate |\n| Market size (planner software) | ~$54M TAM | 45k planners × $1,200/yr avg |\n\n**Trend**: The wedding industry recovered to pre-COVID levels by 2022 and has sustained a "wedding boom" through 2024 with elevated demand. Planners are booked further in advance (18+ months) and managing more complex multi-vendor events.\n\n## 3. Competitive Landscape\n\n| Product | Type | Price/mo | Key Weakness |\n|---------|------|----------|-------------|\n| Aisle Planner | Wedding planner suite | $49-$99 | Dated UI, poor mobile experience |\n| Honeybook | CRM + proposals | $16-$66 | Not wedding-specific, weak timeline tools |\n| Planning Pod | Full event suite | $49-$199 | Designed for venues, overkill for planners |\n| Trello / Asana | Generic PM | $0-$25 | No wedding logic, no client portal |\n| Google Sheets | Manual | Free | No automation, no client-facing layer |\n| **WeddingOS** | **Planner-native** | **$49-$99** | **New entrant** |\n\n**Key Insight**: Existing tools either come from the venue/caterer side (too heavy) or the general CRM side (missing wedding workflow). Independent planners are an underserved middle layer.\n\n## 4. Target User Personas\n\n### Persona A: Amanda - The Established Solo Planner\n- **Age**: 36, female, Charleston SC\n- **Volume**: 24 weddings/year, full-service at $5,500 avg fee\n- **Annual revenue**: ~$132,000\n- **Current tools**: Aisle Planner (hates the UX), Google Sheets for budget, Gmail threads for vendor comms\n- **Pain Points**:\n  1. Client couples constantly ask "what''s next" — no shared timeline view\n  2. Vendor contact info scattered across email and her phone\n  3. Budget tracking in spreadsheets breaks when vendors change their quotes\n  4. Day-of timeline lives in a Word doc that she prints and prays nothing changes\n- **Goal**: Look more professional to high-end clients, reduce repeat questions\n- **Willingness to pay**: $79/month (less than one hour of her billable rate)\n\n### Persona B: Marcus - The Part-Time Planner Going Full-Time\n- **Age**: 29, male, Austin TX\n- **Volume**: 16 weddings/year, building toward 25\n- **Current tools**: Notion for everything (over-engineered setup)\n- **Pain Points**:\n  1. Spends 3+ hours setting up Notion for each new client\n  2. Client portal in Notion looks messy and unprofessional\n  3. No automated reminders for vendor payment deadlines\n- **Goal**: Present as professional as larger planning firms\n- **Willingness to pay**: $49-$59/month, sensitive to price as he''s still growing\n\n### Persona C: Diana - The High-Volume Coordinator\n- **Age**: 44, female, New York\n- **Volume**: 30 weddings/year, day-of coordination specialist\n- **Pain Points**:\n  1. Managing vendor call sheets for 30 events is a copy-paste nightmare\n  2. Client handoff (from full planner to her day-of) loses critical info\n  3. Needs mobile-optimized day-of view for running timelines on-site\n- **Specific need**: Day-of execution mode with real-time vendor contact access\n- **Willingness to pay**: $79-$99/month for mobile-first timeline features\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|----------|---------|-------------|\n| P0 | Client project dashboard | Per-wedding workspace with timeline, budget, vendor list, checklist |\n| P0 | Shared client portal | Read-only view for couples showing their wedding progress, upcoming to-dos |\n| P0 | Vendor contact book | Centralized vendor CRM with contract status, payment due dates, contact info |\n| P0 | Budget tracker | Line-item budget with actual vs. estimated, payment status per vendor |\n| P0 | Master timeline builder | Drag-and-drop day-of timeline, exportable to PDF |\n| P1 | Automated reminders | Email clients and vendors for upcoming deadlines, payments, decisions |\n| P1 | Document vault | Store contracts, inspiration images, floor plans per wedding |\n| P1 | Proposal + contract templates | Send proposals, collect digital signatures |\n| P1 | Multi-wedding calendar view | See all active weddings in one calendar |\n| P2 | Vendor portal (limited) | Vendors can confirm participation, upload documents |\n| P2 | Mobile day-of mode | Simplified real-time view for on-site timeline management |\n| P2 | Reporting & billing | Track planner hours, generate invoices |\n\n## 6. Technical Architecture\n\n```\nFrontend:\n  - Planner dashboard: Next.js 15 + TailwindCSS\n    - Multi-wedding sidebar nav\n    - Drag-and-drop timeline (using dnd-kit)\n    - PDF export via @react-pdf/renderer\n  - Client portal: Separate subdomain (client.weddingos.com/{slug})\n    - Read-only, no auth required (magic link access)\n\nBackend:\n  - Go + Echo v4 (REST API)\n  - Background jobs: Email reminders (cron), document processing\n  - File storage: AWS S3 (contracts, photos, floor plans)\n  - E-signatures: HelloSign API (Dropbox Sign)\n\nData:\n  - PostgreSQL 16 (weddings, vendors, timeline events, budget items)\n  - Redis (session, rate limiting)\n\nNotifications:\n  - SendGrid (client and vendor reminder emails)\n  - Optional Twilio SMS for day-of critical alerts\n\nDeployment:\n  - Fly.io (API) + Vercel (frontend + client portal)\n```\n\n## 7. Business Model\n\n| Plan | Price | Weddings Supported | Key Features |\n|------|-------|-------------------|-------------|\n| Starter | $49/mo | Up to 10 active | Core dashboard, client portal, budget tracker |\n| Pro | $79/mo | Up to 25 active | + reminders, document vault, proposals |\n| Studio | $99/mo | Unlimited | + team members, vendor portal, priority support |\n| Annual discount | 20% off | All plans | Billed annually |\n\n**Revenue Projection**:\n- Month 6: 150 paid planners avg $72/mo = $10,800 MRR\n- Month 12: 400 paid planners avg $78/mo = $31,200 MRR\n- Churn target: <4%/month (high switching cost once data is in)\n\n## 8. MVP Roadmap\n\n| Milestone | Duration | Deliverables | Gate |\n|-----------|----------|-------------|------|\n| M1: Core workspace | 6 weeks | Wedding dashboard, vendor CRM, budget tracker | 10 beta planners |\n| M2: Client portal | 3 weeks | Shared client view, magic link access | Client NPS ≥45 |\n| M3: Timeline + reminders | 4 weeks | Timeline builder, automated reminders, PDF export | 80% weekly active usage |\n| M4: Growth features | 4 weeks | Proposals, document vault, referral program | 60 paying planners |\n\n## 9. Success Metrics\n\n| KPI | 6-Month Target | 12-Month Target |\n|-----|---------------|----------------|\n| Registered planners | 500 | 1,500 |\n| Paid subscribers | 180 | 550 |\n| MRR | $12,600 | $42,000 |\n| Avg weddings managed per planner | 18 | 22 |\n| Client portal adoption | 75% of active planners | 88% |\n| Monthly churn rate | <4% | <3% |\n| NPS (planners) | ≥50 | ≥58 |\n\n## 10. Risks & Mitigation\n\n| Risk | Severity | Probability | Mitigation |\n|------|----------|-------------|------------|\n| Data migration from existing tools is painful | High | High | Build importers for Aisle Planner and Google Sheets CSV |\n| Planners resist changing workflow mid-busy season | High | High | Target January-March (slow season) for onboarding campaigns |\n| E-signature compliance in multiple states | Medium | Medium | Use established provider (Dropbox Sign), inherit their compliance |\n| Client portal link security concerns | Medium | Low | Magic link expiry + optional password protection |\n| Competition from Honeybook expanding wedding features | High | Medium | Focus depth on wedding-specific workflow that CRMs won''t prioritize |',
    E'[{"step":"Target sharpening","decision":"Focus on independent planners handling 15-30 weddings, not coordinators or venue staff","reason":"This segment has the clearest pain and sufficient revenue to support a $79/mo tool; venue staff have different buyers (their employer)"},{"step":"Client portal design","decision":"Magic-link access, no client account required","reason":"Couples use the portal for 12 months max; forcing them to create accounts adds friction with no retention benefit"},{"step":"Core P0 scope","decision":"Include budget tracker in MVP, not just timeline","reason":"Budget overruns are the #1 source of client complaints; solving timeline without budget gives incomplete value"},{"step":"Pricing","decision":"Three-tier at $49/$79/$99","reason":"$49 captures price-sensitive growing planners; $79 is the sweet spot for established solo planners; $99 unlocks team features for small firms"},{"step":"Technical","decision":"PDF timeline export is P0, not P1","reason":"Planners print and distribute day-of timelines to vendors and couples; this is non-negotiable for professional use"},{"step":"Go-to-market","decision":"Partner with Wedding International Professionals Association (WIPA) and regional planner guilds","reason":"Planners trust peer recommendations over ads; guild endorsement is equivalent to 1,000 cold email campaigns"}]',
    'submitted', 47, NOW() - INTERVAL '22 days', NOW() - INTERVAL '23 days', NOW() - INTERVAL '22 days'),

