INSERT INTO contributions (idea_id, author_id, content, decision_log, status, view_count, submitted_at, created_at, updated_at) VALUES
(18, 6, E'# TablePulse - Review Generation & Reputation Management for Independent Restaurants\n\n## 1. Executive Summary\n\nTablePulse is a reputation management platform for independent restaurant owners who want to generate more positive reviews, monitor sentiment across platforms, and respond to feedback without spending hours online. The product''s core mechanic is a QR table card system: happy diners scan at the table and are guided to leave a Google or Yelp review in under 60 seconds. Negative feedback is intercepted privately, allowing the owner to address it before it becomes a public 1-star review.\n\n**Core Insight**: 85% of diners read reviews before choosing a restaurant, yet most independent restaurants have fewer than 50 Google reviews. The review gap between chains (who actively solicit reviews) and independents is the #1 competitive disadvantage TablePulse closes.\n\n**Target**: Independent restaurant owners in the US with 1-3 locations, $500K-$3M annual revenue, who personally manage or closely supervise operations.\n\n## 2. Market Analysis\n\n| Metric | Data | Source |\n|--------|------|--------|\n| Independent restaurants in US | ~500,000 | NRA 2023 |\n| % with <50 Google reviews | ~62% | BrightLocal |\n| Avg new reviews/month (active chain) | 25-40 | Industry estimate |\n| Avg new reviews/month (independent) | 2-4 | Industry estimate |\n| 1-star review impact on revenue | -5 to -9% | Harvard Business School |\n| Yelp rating 1-star increase impact | +5-9% revenue | HBS study |\n| Restaurants using review management tools | <15% | Podium survey |\n| Review software TAM (independents) | ~$600M/yr | 500k × $1,200 avg |\n\n**The math for restaurant owners**: Getting from 3.8 to 4.2 stars on Google can increase monthly covers by 15-20%. TablePulse''s entire value proposition can be expressed as a star rating improvement.\n\n## 3. Competitive Landscape\n\n| Product | Positioning | Price/mo | Key Weakness |\n|---------|------------|----------|-------------|\n| Podium | SMS-first review platform | $399-$599 | Too expensive for small restaurants |\n| Birdeye | Full reputation suite | $299-$499 | Enterprise-oriented, complex |\n| Broadly | Local business reputation | $199-$299 | Not restaurant-specific |\n| Grade.us | Review generation | $110-$300 | No sentiment analysis, no QR |\n| Google Business Profile | Free review management | Free | No proactive generation, no interception |\n| **TablePulse** | **Restaurant-native QR reviews** | **$79-$149** | **New entrant** |\n\n## 4. Target User Personas\n\n### Persona A: Mike - The Proud Owner Watching His Star Drop\n- **Age**: 47, male, Portland OR\n- **Restaurant**: Italian trattoria, 12 years open, ~180 covers/night\n- **Problem**: A string of unfair 1-star reviews (one from a competitor, he suspects) dropped him from 4.4 to 4.1 stars; he can''t figure out how to get good reviews to balance them out\n- **Current approach**: Verbally asks regulars to "leave us a review" — inconsistent, forgotten\n- **Tech comfort**: Moderate; uses Square POS and Toast for reservations\n- **Pain point**: Spends 2+ hours/week manually responding to reviews, often emotionally\n- **Willingness to pay**: $99-$129/month if it demonstrably improves his rating\n\n### Persona B: Sarah - The New Restaurant Owner Building a Reputation\n- **Age**: 34, female, Austin TX\n- **Restaurant**: Farm-to-table cafe, 18 months open, growing steadily\n- **Problem**: Only 23 Google reviews despite excellent food; new customers can''t find her because her rating isn''t established enough to rank in local search\n- **Goal**: Get to 100+ reviews quickly to establish trust; focus positive energy on review building\n- **Tech comfort**: High; active on Instagram, uses reservation software\n- **Willingness to pay**: $79-$99/month\n\n### Persona C: Carlos - The Multi-Location Operator\n- **Age**: 52, male, Miami FL\n- **Restaurants**: 3 Mexican casual dining locations\n- **Problem**: One location has 4.5 stars, another has 3.8; needs to identify why and fix it\n- **Goal**: Cross-location sentiment analysis to identify training/quality issues before they become public\n- **Need**: Centralized dashboard across all 3 locations\n- **Willingness to pay**: $149-$199/month for multi-location plan\n\n## 5. Core Features\n\n| Priority | Feature | Description |\n|----------|---------|-------------|\n| P0 | QR table card system | Printable QR cards linking to review flow; customer scans, rates experience, routed accordingly |\n| P0 | Review routing (5-star gate) | 4-5 star → guided to Google/Yelp; 1-3 star → private feedback form to owner |\n| P0 | Google Business Profile integration | Auto-pull new reviews, display in dashboard |\n| P0 | Review response templates | Pre-written response templates (positive, neutral, negative) for quick replies |\n| P0 | Review dashboard | All reviews in one place, sorted by recency and platform |\n| P1 | Sentiment analysis | Categorize review themes (food quality, service, wait time, value) |\n| P1 | Auto-response drafts | AI-drafted responses for owner to edit and approve (not auto-send) |\n| P1 | Yelp + TripAdvisor integration | Pull reviews from additional platforms |\n| P1 | Review velocity alerts | Notify owner when review rate drops or a negative review arrives |\n| P2 | Multi-location dashboard | Aggregate and compare rating across 2+ locations |\n| P2 | Staff recognition | Tag server name in positive reviews to recognize staff performance |\n| P2 | Competitor benchmarking | Compare your rating trend vs. nearby competitors |\n\n## 6. Technical Architecture\n\n```\nFrontend:\n  - Owner dashboard: Next.js 15 + TailwindCSS\n  - QR landing page (customer-facing): Static HTML (ultra-fast load)\n    - Mobile-first, loads in <1s on 4G\n    - No app required, browser-native\n\nBackend:\n  - Go + Echo v4\n  - Google Business Profile API (review ingestion + response posting)\n  - Yelp Fusion API (review ingestion)\n  - Sentiment analysis: OpenAI API (GPT-4o for theme classification)\n  - QR code generation: Built-in library\n  - Cron: Daily review sync, alert dispatch\n\nData:\n  - PostgreSQL 16 (reviews, restaurants, feedback, responses)\n  - Redis (rate limiting, session)\n\nNotifications:\n  - SendGrid (negative review alert, weekly digest)\n  - Twilio SMS (critical negative review instant alert)\n\nInfrastructure:\n  - Backend: Fly.io\n  - Frontend: Vercel\n  - QR card PDF generation: Puppeteer\n```\n\n## 7. Business Model\n\n| Plan | Price/mo | Locations | Key Features |\n|------|----------|-----------|-------------|\n| Starter | $79/mo | 1 | QR system, Google integration, review dashboard, response templates |\n| Pro | $129/mo | 1 | + sentiment analysis, AI response drafts, Yelp + TripAdvisor |\n| Multi-Location | $199/mo | Up to 5 | Pro features + cross-location dashboard, benchmarking |\n| Annual discount | 15% off | All plans | — |\n\n**Unit economics**:\n- CAC target: <$150 (via local restaurant association + Facebook/Instagram ads)\n- LTV at Pro plan: $129 × 18 months avg = $2,322\n- LTV:CAC: ~15:1\n\n## 8. MVP Roadmap\n\n| Milestone | Timeframe | Deliverables | Gate |\n|-----------|-----------|-------------|------|\n| M1: QR + routing | 5 weeks | QR card system, review routing gate, private feedback form | 10 beta restaurants |\n| M2: Dashboard | 3 weeks | Google integration, review dashboard, response templates | Avg 3+ new reviews/week per restaurant |\n| M3: Intelligence | 4 weeks | Sentiment analysis, AI response drafts, velocity alerts | Review response rate >60% |\n| M4: Scale | 4 weeks | Yelp integration, multi-location, billing | 50 paying restaurants |\n\n## 9. Success Metrics\n\n| KPI | 3-Month Target | 6-Month Target |\n|-----|---------------|----------------|\n| Registered restaurants | 150 | 400 |\n| Paid subscribers | 60 | 200 |\n| MRR | $6,000 | $22,000 |\n| Avg review velocity increase | 4x baseline | 6x baseline |\n| Avg star rating improvement (3 months on platform) | +0.2 stars | +0.4 stars |\n| Private feedback intercept rate | ≥25% of unhappy diners | ≥30% |\n| Owner NPS | ≥50 | ≥58 |\n\n## 10. Risks & Mitigation\n\n| Risk | Severity | Probability | Mitigation |\n|------|----------|-------------|------------|\n| Google TOS limits review solicitation methods | High | Medium | QR flow directs to Google naturally, not incentivized; monitor TOS carefully |\n| Restaurant owner churn after initial review bump | High | Medium | Shift value story to ongoing sentiment monitoring, not just volume |\n| Diners ignore QR cards at table | Medium | High | Train wait staff to mention it verbally; test different card placements |\n| AI response drafts feel generic | Medium | Medium | Fine-tune on restaurant-specific voice after 2 weeks of owner responses |\n| Negative review interception seen as manipulative | Medium | Low | Frame as "private feedback" not "review blocking"; be transparent in marketing |',
    E'[{"step":"Core mechanic","decision":"QR table card with review routing gate as the primary product","reason":"The routing gate (4-5 stars to Google, 1-3 stars to private form) is the key innovation; it captures the good and deflects the bad without violating any platform TOS"},{"step":"Pricing","decision":"$79 Starter, $129 Pro","reason":"Podium charges $399+ making the market inaccessible to small restaurants; our pricing creates a clear 5x value advantage against the established player"},{"step":"AI responses","decision":"Draft-and-approve, not auto-send","reason":"Restaurant voice and context matter enormously; auto-sent responses that sound robotic damage trust more than slow manual responses"},{"step":"Platform priority","decision":"Google first, Yelp second","reason":"Google drives 80% of local restaurant discovery; Yelp matters for certain cities (SF, NYC) but is a P1 priority not MVP"},{"step":"Customer success","decision":"Include staff training materials in onboarding","reason":"QR card success depends on server behavior; owner buy-in is necessary but not sufficient without staff awareness"},{"step":"Expansion signal","decision":"Multi-location as upsell, not bundled","reason":"Single-location validation first; multi-location at $199 captures the 3-location operator segment without overcomplicating MVP"}]',
    'submitted', 55, NOW() - INTERVAL '20 days', NOW() - INTERVAL '21 days', NOW() - INTERVAL '20 days'),

